import React, { useState, useMemo, useEffect, useRef } from 'react';

const theme = {
  bg: '#0a0a0a', surface: '#111111', surfaceAlt: '#1a1a1a',
  border: '#2a2a2a', text: '#fafafa', textSec: '#a1a1aa', muted: '#52525b',
  primary: '#8b5cf6', blue: '#38bdf8', green: '#a3e635',
  yellow: '#fbbf24', orange: '#fb923c', pink: '#f472b6', red: '#f87171',
};

const lerp = (a, b, t) => a + (b - a) * t;

export default function App() {
  const [ratio, setRatio] = useState(0.5);
  const [strength, setStrength] = useState(0.2);
  const [animFrame, setAnimFrame] = useState(-1);
  const [playing, setPlaying] = useState(false);
  const timerRef = useRef(null);

  const X = useMemo(() => [
    [1, 0.5], [2, 2.1], [3, 2.4], [4, 4.5], [5, 5.2],
    [1.5, 1.2], [2.5, 1.8], [3.5, 3.2], [4.5, 4.0]
  ], []);
  const y = useMemo(() => [1.2, 3.8, 5.0, 8.0, 9.8, 2.5, 3.8, 6.2, 7.8], []);

  const alpha1 = strength * ratio;
  const alpha2 = strength * (1 - ratio);

  const runGD = (a1, a2, lr, maxIter) => {
    const n = X.length;
    let w = [0, 0], b = 0;
    const path = [{ w: [...w], b }];
    for (let iter = 0; iter < maxIter; iter++) {
      const yP = X.map(xi => xi[0] * w[0] + xi[1] * w[1] + b);
      const err = yP.map((p, i) => p - y[i]);
      const g0 = X.reduce((s, xi, i) => s + xi[0] * err[i], 0) / n + a1 * Math.sign(w[0]) + 2 * a2 * w[0];
      const g1 = X.reduce((s, xi, i) => s + xi[1] * err[i], 0) / n + a1 * Math.sign(w[1]) + 2 * a2 * w[1];
      const gb = err.reduce((s, e) => s + e, 0) / n;
      w = [w[0] - lr * g0, w[1] - lr * g1];
      b -= lr * gb;
      path.push({ w: [...w], b });
      if (Math.abs(g0) + Math.abs(g1) < 1e-5) break;
    }
    return { path, finalW: [...w], finalB: b };
  };

  const result = useMemo(() => runGD(alpha1, alpha2, 0.01, 300), [alpha1, alpha2]);
  const olsW = useMemo(() => runGD(0, 0, 0.01, 500).finalW, []);

  const totalFrames = result.path.length;
  const dispFrame = animFrame === -1 ? totalFrames - 1 : Math.min(animFrame, totalFrames - 1);

  useEffect(() => {
    if (playing) {
      setAnimFrame(0);
      const id = setInterval(() => {
        setAnimFrame(f => {
          const next = f + 4;
          if (next >= totalFrames - 1) { setPlaying(false); clearInterval(id); return -1; }
          return next;
        });
      }, 40);
      timerRef.current = id;
    }
    return () => clearInterval(timerRef.current);
  }, [playing, totalFrames]);

  const handlePlay = () => { if (!playing) { setPlaying(true); } };
  const handleReset = () => { setPlaying(false); clearInterval(timerRef.current); setAnimFrame(-1); };

  const hessian = useMemo(() => {
    const n = X.length;
    let h00 = 0, h01 = 0, h11 = 0;
    for (let i = 0; i < n; i++) { h00 += X[i][0] ** 2; h01 += X[i][0] * X[i][1]; h11 += X[i][1] ** 2; }
    return { h00: h00 / n, h01: h01 / n, h11: h11 / n };
  }, [X]);

  const eigen = useMemo(() => {
    const { h00, h01, h11 } = hessian;
    const tr = h00 + h11, det = h00 * h11 - h01 * h01;
    const disc = Math.sqrt(Math.max(0, tr * tr / 4 - det));
    const l1 = tr / 2 + disc, l2 = Math.max(0.01, tr / 2 - disc);
    const angle = Math.atan2(2 * h01, h00 - h11) / 2;
    return { l1, l2, angle };
  }, [hessian]);

  const penaltyPoints = useMemo(() => {
    const pts = [];
    const steps = 120;
    const budget = Math.max(0.05, 0.6 / Math.max(strength, 0.01));
    for (let i = 0; i <= steps; i++) {
      const t = (i / steps) * 2 * Math.PI;
      const ct = Math.cos(t), st = Math.sin(t);
      const ac = Math.abs(ct), as2 = Math.abs(st);
      let r;
      if (alpha2 > 0.001 && alpha1 > 0.001) {
        const a = alpha2, bc = alpha1 * (ac + as2);
        r = (-bc + Math.sqrt(bc * bc + 4 * a * budget)) / (2 * a);
      } else if (alpha2 > 0.001) {
        r = Math.sqrt(budget / alpha2);
      } else if (alpha1 > 0.001) {
        r = budget / (alpha1 * (ac + as2 + 0.001));
      } else { r = 3; }
      r = Math.min(r, 4);
      pts.push([r * ct, r * st]);
    }
    return pts;
  }, [alpha1, alpha2, strength]);

  const wRange = { min: -0.3, max: 2.2 };
  const svgW = 380, svgH = 300;
  const toX = w => ((w - wRange.min) / (wRange.max - wRange.min)) * svgW;
  const toY = w => svgH - ((w - wRange.min) / (wRange.max - wRange.min)) * svgH;

  const curW = result.path[dispFrame]?.w || result.finalW;
  const curB = result.path[dispFrame]?.b || result.finalB;

  const ellipsePaths = useMemo(() => {
    const { l1, l2, angle } = eigen;
    const scales = [0.4, 0.8, 1.4, 2.2];
    return scales.map(s => {
      const pts = [];
      for (let i = 0; i <= 60; i++) {
        const t = (i / 60) * 2 * Math.PI;
        const ex = s / Math.sqrt(l1) * Math.cos(t);
        const ey = s / Math.sqrt(l2) * Math.sin(t);
        const rx = ex * Math.cos(angle) - ey * Math.sin(angle) + olsW[0];
        const ry = ex * Math.sin(angle) + ey * Math.cos(angle) + olsW[1];
        pts.push(`${toX(rx)},${toY(ry)}`);
      }
      return `M${pts.join('L')}Z`;
    });
  }, [eigen, olsW]);

  const penPath = useMemo(() => {
    if (penaltyPoints.length === 0) return '';
    return 'M' + penaltyPoints.map(p => `${toX(p[0])},${toY(p[1])}`).join('L') + 'Z';
  }, [penaltyPoints]);

  const gdPathStr = useMemo(() => {
    const frames = result.path.slice(0, dispFrame + 1);
    if (frames.length === 0) return '';
    return frames.map((f, i) => `${i === 0 ? 'M' : 'L'}${toX(f.w[0])},${toY(f.w[1])}`).join('');
  }, [result.path, dispFrame]);

  const penColor = `rgb(${Math.round(lerp(56, 251, ratio))},${Math.round(lerp(189, 146, ratio))},${Math.round(lerp(248, 60, ratio))})`;
  const modeLabel = ratio < 0.15 ? 'Ridge (L2 only)' : ratio > 0.85 ? 'Lasso (L1 only)' : 'Elastic Net (L1 + L2)';

  const presets = [
    { label: 'Pure L1', r: 1.0, s: 0.2 },
    { label: 'Elastic Net', r: 0.5, s: 0.2 },
    { label: 'Pure L2', r: 0.0, s: 0.2 },
    { label: 'Strong Reg', r: 0.5, s: 0.5 },
  ];

  const w1near0 = Math.abs(curW[0]) < 0.05;
  const w2near0 = Math.abs(curW[1]) < 0.05;
  const sparsity = (w1near0 ? 1 : 0) + (w2near0 ? 1 : 0);

  let insight = '';
  if (ratio > 0.8 && sparsity > 0) insight = 'L1 dominance drives weights to exactly zero - achieving sparsity! The diamond shape has corners on axes where weights vanish.';
  else if (ratio > 0.8) insight = 'High L1 ratio pushes weights toward zero. Increase strength to see a weight vanish entirely.';
  else if (ratio < 0.2) insight = 'Pure L2 shrinks all weights evenly but never to zero. Notice both weights stay active - no sparsity.';
  else if (strength > 0.4) insight = 'Strong regularization heavily constrains weights. The rounded diamond shape gives both shrinkage and some sparsity.';
  else insight = 'Elastic Net blends L1 (diamond corners = sparsity) with L2 (smooth = stability). Drag the ratio slider to morph the penalty shape!';

  return (
    <div style={{ background: theme.bg, minHeight: '100vh', display: 'flex', justifyContent: 'center', padding: '12px 8px', fontFamily: "'JetBrains Mono', monospace", color: theme.text, boxSizing: 'border-box' }}>
      <div style={{ maxWidth: 580, width: '100%' }}>
        {/* Header */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 10 }}>
          <div>
            <div style={{ fontSize: 17, fontWeight: 700 }}>Elastic Net Regression</div>
            <div style={{ fontSize: 11, color: theme.textSec }}>{modeLabel}</div>
          </div>
          <div style={{ display: 'flex', gap: 6 }}>
            <button onClick={handlePlay} disabled={playing} style={{ background: theme.primary, border: 'none', color: '#fff', borderRadius: 6, padding: '5px 12px', fontSize: 12, cursor: 'pointer', opacity: playing ? 0.5 : 1 }}>Play</button>
            <button onClick={handleReset} style={{ background: theme.surfaceAlt, border: `1px solid ${theme.border}`, color: theme.textSec, borderRadius: 6, padding: '5px 10px', fontSize: 12, cursor: 'pointer' }}>Reset</button>
          </div>
        </div>

        {/* Presets */}
        <div style={{ display: 'flex', gap: 5, marginBottom: 10 }}>
          {presets.map(p => {
            const active = Math.abs(ratio - p.r) < 0.05 && Math.abs(strength - p.s) < 0.05;
            return (
              <button key={p.label} onClick={() => { setRatio(p.r); setStrength(p.s); setAnimFrame(-1); setPlaying(false); clearInterval(timerRef.current); }}
                style={{ flex: 1, background: active ? theme.primary : theme.surfaceAlt, border: `1px solid ${active ? theme.primary : theme.border}`, color: active ? '#fff' : theme.textSec, borderRadius: 6, padding: '4px 6px', fontSize: 10, cursor: 'pointer' }}>
                {p.label}
              </button>
            );
          })}
        </div>

        {/* Main SVG */}
        <div style={{ background: theme.surface, borderRadius: 10, padding: '10px 6px 6px', marginBottom: 10 }}>
          <div style={{ display: 'flex', gap: 10 }}>
            <svg viewBox={`0 0 ${svgW} ${svgH}`} style={{ width: '100%', maxWidth: 380, background: theme.surfaceAlt, borderRadius: 8 }}>
              {/* Loss contours */}
              {ellipsePaths.map((d, i) => (
                <path key={i} d={d} fill="none" stroke={theme.muted} strokeWidth={0.7} opacity={0.3 + i * 0.05} strokeDasharray={i === 0 ? 'none' : '3,3'} />
              ))}

              {/* Penalty region */}
              <path d={penPath} fill={penColor} fillOpacity={0.08} stroke={penColor} strokeWidth={1.5} strokeOpacity={0.5} />

              {/* Axes */}
              <line x1={toX(0)} y1={toY(wRange.min)} x2={toX(0)} y2={toY(wRange.max)} stroke={theme.muted} strokeWidth={0.5} opacity={0.3} />
              <line x1={toX(wRange.min)} y1={toY(0)} x2={toX(wRange.max)} y2={toY(0)} stroke={theme.muted} strokeWidth={0.5} opacity={0.3} />
              <text x={svgW - 8} y={toY(0) - 6} fill={theme.textSec} fontSize={10} textAnchor="end">w1</text>
              <text x={toX(0) + 6} y={14} fill={theme.textSec} fontSize={10}>w2</text>

              {/* OLS point */}
              <circle cx={toX(olsW[0])} cy={toY(olsW[1])} r={5} fill="none" stroke={theme.muted} strokeWidth={1} strokeDasharray="2,2" />
              <circle cx={toX(olsW[0])} cy={toY(olsW[1])} r={1.5} fill={theme.muted} />
              <text x={toX(olsW[0]) + 8} y={toY(olsW[1]) + 4} fill={theme.muted} fontSize={8}>OLS</text>

              {/* GD path */}
              {gdPathStr && <path d={gdPathStr} fill="none" stroke={theme.green} strokeWidth={1.5} opacity={0.7} />}

              {/* Current point */}
              <circle cx={toX(curW[0])} cy={toY(curW[1])} r={6} fill={theme.green} opacity={0.25} />
              <circle cx={toX(curW[0])} cy={toY(curW[1])} r={3.5} fill={theme.green} />

              {/* Origin */}
              <circle cx={toX(0)} cy={toY(0)} r={2} fill={theme.muted} opacity={0.4} />

              {/* Labels for penalty shape */}
              {ratio > 0.7 && <text x={toX(0) + 4} y={toY(0) + 14} fill={penColor} fontSize={8} opacity={0.7}>diamond = sparsity</text>}
              {ratio < 0.3 && <text x={toX(0) + 4} y={toY(0) + 14} fill={penColor} fontSize={8} opacity={0.7}>circle = no sparsity</text>}
            </svg>

            {/* Weight display */}
            <div style={{ minWidth: 140, display: 'flex', flexDirection: 'column', gap: 8, justifyContent: 'center' }}>
              <div style={{ fontSize: 10, color: theme.textSec, marginBottom: 2 }}>WEIGHTS</div>
              {[{ label: 'w1', val: curW[0], ols: olsW[0] }, { label: 'w2', val: curW[1], ols: olsW[1] }].map(({ label, val, ols }) => (
                <div key={label}>
                  <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11 }}>
                    <span style={{ color: theme.textSec }}>{label}</span>
                    <span style={{ color: Math.abs(val) < 0.05 ? theme.orange : theme.green, fontWeight: 700 }}>{val.toFixed(3)}</span>
                  </div>
                  <div style={{ height: 8, background: theme.bg, borderRadius: 4, marginTop: 3, overflow: 'hidden', position: 'relative' }}>
                    <div style={{ position: 'absolute', left: 0, top: 0, height: '100%', width: `${Math.min(100, (Math.abs(ols) / 2) * 100)}%`, background: theme.muted, opacity: 0.2, borderRadius: 4 }} />
                    <div style={{ position: 'absolute', left: 0, top: 0, height: '100%', width: `${Math.min(100, (Math.abs(val) / 2) * 100)}%`, background: Math.abs(val) < 0.05 ? theme.orange : theme.green, borderRadius: 4, transition: 'width 0.15s' }} />
                  </div>
                  <div style={{ fontSize: 9, color: theme.muted, marginTop: 1 }}>OLS: {ols.toFixed(3)}</div>
                </div>
              ))}
              <div style={{ borderTop: `1px solid ${theme.border}`, paddingTop: 8, marginTop: 4 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11 }}>
                  <span style={{ color: theme.textSec }}>bias</span>
                  <span style={{ color: theme.blue, fontWeight: 700 }}>{curB.toFixed(3)}</span>
                </div>
              </div>
              <div style={{ marginTop: 8, padding: '6px 8px', background: theme.bg, borderRadius: 6, fontSize: 10 }}>
                <div style={{ color: theme.textSec, marginBottom: 3 }}>Sparsity</div>
                <div style={{ color: sparsity > 0 ? theme.orange : theme.textSec, fontWeight: 700 }}>
                  {sparsity > 0 ? `${sparsity}/2 weights at zero` : 'No zero weights'}
                </div>
              </div>
              <div style={{ padding: '6px 8px', background: theme.bg, borderRadius: 6, fontSize: 10 }}>
                <div style={{ color: theme.textSec, marginBottom: 3 }}>Iterations</div>
                <div style={{ fontWeight: 700 }}>{dispFrame + 1} / {totalFrames}</div>
              </div>
            </div>
          </div>

          {/* Legend */}
          <div style={{ display: 'flex', gap: 14, marginTop: 8, padding: '0 4px', fontSize: 9, color: theme.textSec }}>
            <span><span style={{ display: 'inline-block', width: 8, height: 8, borderRadius: '50%', background: theme.muted, marginRight: 4, verticalAlign: 'middle', opacity: 0.5 }}></span>Loss contours (OLS)</span>
            <span><span style={{ display: 'inline-block', width: 8, height: 8, borderRadius: 2, background: penColor, marginRight: 4, verticalAlign: 'middle', opacity: 0.5 }}></span>Penalty region</span>
            <span><span style={{ display: 'inline-block', width: 8, height: 8, borderRadius: '50%', background: theme.green, marginRight: 4, verticalAlign: 'middle' }}></span>GD path</span>
          </div>
        </div>

        {/* Controls */}
        <div style={{ background: theme.surface, borderRadius: 10, padding: 12, marginBottom: 10 }}>
          <div style={{ marginBottom: 10 }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11, marginBottom: 4 }}>
              <span style={{ color: theme.textSec }}>L1/L2 Ratio</span>
              <span style={{ color: penColor, fontWeight: 600 }}>a1={alpha1.toFixed(3)} a2={alpha2.toFixed(3)}</span>
            </div>
            <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <span style={{ fontSize: 9, color: theme.blue, minWidth: 22 }}>L2</span>
              <input type="range" min={0} max={1} step={0.01} value={ratio}
                onChange={e => { setRatio(+e.target.value); setAnimFrame(-1); }}
                style={{ flex: 1, accentColor: penColor }} />
              <span style={{ fontSize: 9, color: theme.orange, minWidth: 22, textAlign: 'right' }}>L1</span>
            </div>
          </div>
          <div>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 11, marginBottom: 4 }}>
              <span style={{ color: theme.textSec }}>Regularization Strength</span>
              <span style={{ fontWeight: 600, color: theme.textSec }}>{strength.toFixed(2)}</span>
            </div>
            <input type="range" min={0.01} max={0.6} step={0.01} value={strength}
              onChange={e => { setStrength(+e.target.value); setAnimFrame(-1); }}
              style={{ width: '100%', accentColor: theme.primary }} />
          </div>
        </div>

        {/* Insight */}
        <div style={{ background: theme.surface, borderRadius: 10, padding: '10px 14px', fontSize: 11, color: theme.textSec, lineHeight: 1.5, borderLeft: `3px solid ${penColor}` }}>
          <span style={{ color: penColor, fontWeight: 600 }}>Insight: </span>{insight}
        </div>
      </div>
    </div>
  );
}
